// === meet-to-inbox: auth check + normalize into m2 schema-v1 capture ===
// This is the body of integrations/n8n/normalize.js, inlined for the n8n Code node, plus a
// shared-secret check on the inbound POST. Keep in lock-step with normalize.js (its test guards it).
//
// Inbound (from the Apps Script poller, JSON body):
//   { secret, transcript, captured, title?, participants?, file?, tags? }
// Env (n8n: Settings → Variables, or container env):
//   N8N_WEBHOOK_SECRET  — shared secret the poller must present

const body = $input.first().json.body || $input.first().json;

// --- 1. authenticate the caller (reject unauthenticated POSTs) ---
const expected = $env.N8N_WEBHOOK_SECRET;
if (!expected) { throw new Error('meet-to-inbox: N8N_WEBHOOK_SECRET is not set on this n8n instance'); }
if (!body || body.secret !== expected) {
  // Surface as a clean 401 via the error branch / Respond node.
  throw new Error('meet-to-inbox: bad or missing shared secret');
}

// --- 2. normalize (mirror of normalize.js buildCapture) ---
const p2 = (n) => String(n).padStart(2, '0');
const stampFromISO = (iso) => { const d = new Date(iso); if (Number.isNaN(d.getTime())) throw new Error(`invalid 'captured': ${iso}`); return `${d.getUTCFullYear()}-${p2(d.getUTCMonth()+1)}-${p2(d.getUTCDate())}-${p2(d.getUTCHours())}${p2(d.getUTCMinutes())}`; };
const canonicalISO = (iso) => { const d = new Date(iso); if (Number.isNaN(d.getTime())) throw new Error(`invalid 'captured': ${iso}`); return d.toISOString().replace(/\.\d{3}Z$/, 'Z'); };
const yamlStr = (s) => `"${String(s).replace(/\\/g,'\\\\').replace(/"/g,'\\"')}"`;
const yamlList = (items) => `[${items.map((it)=>{const s=String(it).trim(); return /^[A-Za-z0-9_\-.]+$/.test(s)?s:yamlStr(s);}).join(', ')}]`;

const transcript = body.transcript;
if (typeof transcript !== 'string' || transcript.trim() === '') throw new Error("'transcript' is required");
if (!body.captured) throw new Error("'captured' (ISO-8601 UTC) is required");

const capturedISO = canonicalISO(body.captured);
const stamp = stampFromISO(body.captured);
let title = (body.title || '').trim();
if (!title) { const fl = transcript.trim().split('\n')[0].replace(/\s+/g,' ').slice(0,80); title = fl ? `Meeting transcript — ${fl}` : `Meeting transcript (${stamp})`; }
const participants = Array.isArray(body.participants) ? body.participants.map((x)=>String(x).trim()).filter(Boolean) : [];
const tags = Array.isArray(body.tags) ? body.tags.map((x)=>String(x).trim()).filter(Boolean) : [];
const file = (body.file || '').trim();

const fm = ['---','source:    meet',`captured:  ${capturedISO}`,`title:     ${yamlStr(title)}`];
if (participants.length) fm.push(`participants: ${yamlList(participants)}`);
if (file) fm.push(`file:      ${yamlStr(file)}`);
if (tags.length) fm.push(`tags:      ${yamlList(tags)}`);
fm.push('---');
const content = `${fm.join('\n')}\n\n${transcript.replace(/\s+$/,'')}\n`;
const filename = `meet-${stamp}.md`;

// --- 3. emit fields the GitHub PUT node consumes ---
return [{ json: {
  path: `_inbox/${filename}`,
  filename,
  capturedISO,
  // GitHub Contents API wants base64-encoded content
  contentB64: Buffer.from(content, 'utf8').toString('base64'),
  commitMessage: `feat(inbox): meet capture ${filename}`,
  // repo target is an env var — NOT parsed from brain.config.yml (set BRAIN_REPO per deployment)
  brainRepo: $env.BRAIN_REPO || 'your-org/brain',
  branch: $env.BRAIN_BRANCH || 'main'
} }];

